    p4: '/Avatars/pet-golden-wyvern.png',
    p5: null,
    p6: null,
  },
};

// ─── Sitting Avatar (layered) ─────────────────────────────────────────────────
const SittingAvatar = ({ selections }) => {
  const style    = selections.hairStyle || 'hs1';
  const color    = selections.hairColor || 'hc1';

  // Map hair color ID to color name
  const colorMap = { hc1:'black', hc2:'brown', hc3:'blonde' };
  const colorName = colorMap[color] || 'brown';

  const hairKey  = `${style}_${colorName}`;
  const hairImg  = AVATAR_IMAGES.hair[hairKey] || null;
  const armourImg = AVATAR_IMAGES.armour[selections.armour] || null;

  return (
    <div className="avatar-img-wrapper">
      {/* Base avatar */}
      <img
        src="/Avatars/sittingavatar.jpg"
        alt="avatar"
        className="avatar-base-img"
        onError={(e) => { e.target.src = '/Avatars/sittingavatar.jpg'; }}
      />
      {/* Armour overlay — below hair */}
      {armourImg && (
        <img
          src={armourImg}
          alt="armour"
          className="avatar-layer-img"
          onError={(e) => { e.target.style.display = 'none'; }}
        />
      )}
      {/* Hair overlay — on top of armour */}
      {hairImg && (
        <img
          src={hairImg}
          alt="hair"
          className="avatar-layer-img"
          onError={(e) => { e.target.style.display = 'none'; }}
        />
      )}
    </div>
  );
};

// ─── Pixel Pet ────────────────────────────────────────────────────────────────
const PixelPet = ({ pet }) => {
  if (!pet) return null;

  // Use real image if available
  const petImg = AVATAR_IMAGES.pets[pet.id];
  if (petImg) {
    return (
      <img
        src={petImg}
        alt={pet.label}
        style={{ width: 110, height: 110, objectFit:'contain', imageRendering:'pixelated', display:'block' }}
        onError={(e) => { e.target.style.display='none'; }}
      />
    );
  }

  const c  = pet.color;
  const dk = '#1a1008';
  const S2 = 3;
  const Px2 = ({ x, y, col }) => (
    <rect x={x*S2} y={y*S2} width={S2} height={S2} fill={col} />
  );
  const lighter = c + 'cc';
  return (
    <svg viewBox={`0 0 ${10*S2} ${12*S2}`} width={10*S2*2.2} height={12*S2*2.2}
      style={{ imageRendering: 'pixelated', display:'block' }}
      xmlns="http://www.w3.org/2000/svg">
      <ellipse cx={5*S2} cy={11.6*S2} rx={3.5*S2} ry={S2*0.5} fill="#00000033" />
      <Px2 x={1} y={0} col={c} /><Px2 x={2} y={0} col={c} />
      <Px2 x={7} y={0} col={c} /><Px2 x={8} y={0} col={c} />
      <Px2 x={1} y={1} col={c} /><Px2 x={8} y={1} col={c} />
      {[2,3,4,5,6,7].map(x=><Px2 key={`ph${x}`} x={x} y={1} col={dk}/>)}
      {[1,8].map(x=>[2,3,4].map(y=><Px2 key={`phs${x}${y}`} x={x} y={y} col={dk}/>))}
      {[2,3,4,5,6,7].map(x=><Px2 key={`ph2${x}`} x={x} y={5} col={dk}/>)}
      {[2,3,4,5,6,7].map(x=>[2,3,4].map(y=><Px2 key={`pf${x}${y}`} x={x} y={y} col={c}/>))}
      <Px2 x={3} y={3} col="#ffffff"/><Px2 x={3} y={3} col="#1a0a2e"/>
      <Px2 x={6} y={3} col="#ffffff"/><Px2 x={6} y={3} col="#1a0a2e"/>
      <rect x={3*S2} y={3*S2} width={2} height={2} fill="#ffffffcc"/>
      <rect x={6*S2} y={3*S2} width={2} height={2} fill="#ffffffcc"/>
      <Px2 x={4} y={4} col={lighter}/><Px2 x={5} y={4} col={lighter}/>
      {[2,3,4,5,6,7].map(x=><Px2 key={`pbo${x}`} x={x} y={6} col={dk}/>)}
      {[1,8].map(x=>[6,7,8,9].map(y=><Px2 key={`pbos${x}${y}`} x={x} y={y} col={dk}/>))}
      {[2,3,4,5,6,7].map(x=><Px2 key={`pbo2${x}`} x={x} y={10} col={dk}/>)}
      {[2,3,4,5,6,7].map(x=>[7,8,9].map(y=><Px2 key={`pbf${x}${y}`} x={x} y={y} col={lighter}/>))}
      <Px2 x={2} y={10} col={dk}/><Px2 x={3} y={10} col={dk}/>
      <Px2 x={6} y={10} col={dk}/><Px2 x={7} y={10} col={dk}/>
      <Px2 x={2} y={11} col={dk}/><Px2 x={3} y={11} col={dk}/>
      <Px2 x={6} y={11} col={dk}/><Px2 x={7} y={11} col={dk}/>
      <Px2 x={8} y={9} col={c}/><Px2 x={9} y={8} col={c}/><Px2 x={9} y={7} col={c}/>
    </svg>
  );
};

// ─── Small preview icon ───────────────────────────────────────────────────────
const PreviewIcon = ({ item, category, hairCol }) => {
  if (category === 'skin' || category === 'hairColor') {
    return (
      <div style={{
        width:36, height:36, borderRadius:'50%', background: item.color,
        boxShadow:'inset 0 -2px 4px rgba(0,0,0,0.2), inset 0 2px 4px rgba(255,255,255,0.3)',
        border:'2px solid rgba(0,0,0,0.1)'
      }} />
    );
  }
  if (category === 'pets') {
    const petImg = AVATAR_IMAGES.pets[item.id];
    if (petImg) {
      return (
        <img
          src={petImg}
          alt={item.label}
          style={{ width:42, height:42, objectFit:'contain', borderRadius:6 }}
          onError={(e) => { e.target.style.display='none'; }}
        />
      );
    }
    return <span style={{ fontSize:'1.7rem', filter:'drop-shadow(0 1px 2px rgba(0,0,0,0.3))' }}>{item.emoji}</span>;
  }
  if (category === 'hairStyle') {
    const hairImg = AVATAR_IMAGES.hair[item.id];
    if (hairImg) {
      return (
        <img
          src={hairImg}
          alt={item.label}
          style={{ width:42, height:42, objectFit:'contain', imageRendering:'pixelated', borderRadius:6 }}
          onError={(e) => { e.target.style.display='none'; }}
        />
      );
    }
    // Default hair = show base avatar as preview
    return (
      <img
        src="/Avatars/sittingavatar.jpg"
        alt="default"
        style={{ width:42, height:42, objectFit:'contain', imageRendering:'pixelated', borderRadius:6 }}
      />
    );
  }
  if (category === 'animalEars') {
    return (
      <svg viewBox="3 -3 20 6" width="48" height="20" style={{ imageRendering:'pixelated' }}>
        {item.pixels?.map((px,i)=>(
          <rect key={i} x={px[0]} y={px[1]} width={1} height={1}
            fill={px[2]==='hc'? hairCol : px[2]} />
        ))}
      </svg>
    );
  }
  if (category === 'armour') {
    const imgSrc = AVATAR_IMAGES.armour[item.id];
    const isBase = imgSrc === '/Avatars/sittingavatar.jpg';
    if (!isBase) {
      return (
        <img
          src={imgSrc}
          alt={item.label}
          style={{ width:42, height:42, objectFit:'contain', imageRendering:'pixelated', borderRadius:6 }}
          onError={(e) => { e.target.style.display = 'none'; }}
        />
      );
    }
    // Fallback to pixel art preview for base/locked-no-image items
    return (
      <svg viewBox="6 12 14 8" width="42" height="24" style={{ imageRendering:'pixelated' }}>
        {item.pixels?.map((px,i)=>(
          <rect key={i} x={px[0]} y={px[1]} width={1} height={1} fill={px[2]} />
        ))}
      </svg>
    );
  }
  return <div style={{ width:36, height:36, borderRadius:'50%', background: item.color||'#ccc' }} />;
};

